// Filter valid pins and extract clean image URLs
// Apify alexey~pinterest-crawler returns varied structures
const items = $input.all();
const validPins = [];
const seen = new Set();

function extractUrl(val) {
  if (typeof val === 'string') return val;
  if (val && typeof val === 'object') {
    // Could be {url: '...'} or {orig: {url: '...'}} etc.
    if (val.url) return String(val.url);
    if (val.orig?.url) return String(val.orig.url);
    if (val.orig) return String(val.orig);
    // Try highest-res keys
    for (const k of ['originals', 'orig', '1200x', '736x', '474x', '236x']) {
      if (val[k]?.url) return String(val[k].url);
      if (typeof val[k] === 'string') return val[k];
    }
  }
  return null;
}

for (const item of items) {
  const pin = item.json;

  // Try every known field the crawler might use
  const imageUrl = extractUrl(pin.imageUrl) || extractUrl(pin.image) || extractUrl(pin.images) || extractUrl(pin.thumbnailUrl) || extractUrl(pin.media?.images) || null;
  if (!imageUrl || !imageUrl.startsWith('http')) continue;

  // Get pin ID for dedup
  const pinId = String(pin.id || pin.pinId || pin.url || imageUrl);
  if (seen.has(pinId)) continue;
  seen.add(pinId);

  // Get pin URL
  const pinUrl = String(pin.url || pin.link || (pin.id ? `https://www.pinterest.com/pin/${pin.id}/` : ''));

  validPins.push({
    json: {
      pin_id: pinId,
      image_url: imageUrl,
      title: String(pin.title || pin.name || ''),
      description: String(pin.description || ''),
      pin_url: pinUrl
    }
  });
}

if (validPins.length === 0) {
  // Debug: return first item's keys so we can see the schema
  const sample = items[0]?.json || {};
  return [{ json: { error: 'No valid pins found', count: 0, sampleKeys: Object.keys(sample), sample: JSON.stringify(sample).substring(0, 500) } }];
}

return validPins;

