const geminiResponse = $input.first().json;
const pinData = $('SplitInBatches').first().json;

let outfitPrompt = '';
try {
  outfitPrompt = geminiResponse.candidates[0].content.parts[0].text;
} catch (e) {
  outfitPrompt = `[Gemini analysis failed: ${e.message}] Pin: ${pinData.pin_url}`;
}

// Build look name from pin title or auto-generate
let lookName = pinData.title?.trim();
if (!lookName || lookName.length < 3) {
  lookName = `Pinterest Import — ${pinData.pin_id?.toString().slice(-6) || Date.now()}`;
}
// Truncate if too long for Airtable
if (lookName.length > 100) {
  lookName = lookName.substring(0, 97) + '...';
}

return [{
  json: {
    look_name: lookName,
    outfit_prompt: outfitPrompt.trim(),
    status: 'Pending',
    pinterest_url: pinData.pin_url || '',
    categories_done: 0
  }
}];
